async (params, browser) => {
  // Open top gainers page
  await browser.open('https://www.coinbase.com/explore/s/top-gainers')

  // Wait for content
  await browser.waitForSelector('table, a[href*=\'/price/\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract gainers
  const gainers_data = await browser.evaluate(`const gainers = []; document.querySelectorAll('table tbody tr, a[href*="/price/"]').forEach((el, i) => { if (i >= 15) return; const name = el.querySelector('td:first-child, h2, p')?.textContent?.trim() || el.textContent?.trim() || ''; const price = el.querySelector('td:nth-child(2), [class*="Price"]')?.textContent?.trim() || ''; const change = el.querySelector('td:nth-child(3), [class*="Change"]')?.textContent?.trim() || ''; const link = el.querySelector('a[href*="/price/"]') || (el.matches?.('a[href*="/price/"]') ? el : null); const url = link ? link.href : ''; if (name && name.length < 100) gainers.push({ name, price, change, url }); }); return { gainers, url: window.location.href }`)

  // Open top losers page
  await browser.open('https://www.coinbase.com/explore/s/top-losers')

  // Wait for content
  await browser.waitForSelector('table, a[href*=\'/price/\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract losers
  const losers_data = await browser.evaluate(`const losers = []; document.querySelectorAll('table tbody tr, a[href*="/price/"]').forEach((el, i) => { if (i >= 15) return; const name = el.querySelector('td:first-child, h2, p')?.textContent?.trim() || el.textContent?.trim() || ''; const price = el.querySelector('td:nth-child(2), [class*="Price"]')?.textContent?.trim() || ''; const change = el.querySelector('td:nth-child(3), [class*="Change"]')?.textContent?.trim() || ''; const link = el.querySelector('a[href*="/price/"]') || (el.matches?.('a[href*="/price/"]') ? el : null); const url = link ? link.href : ''; if (name && name.length < 100) losers.push({ name, price, change, url }); }); return { losers, url: window.location.href }`)

  return losers_data
}
